previewCss:
.darma-loader-darma-custom-044 {
  width: 60px;
  aspect-ratio: 1;
  border-radius: 50%;
  -webkit-mask: linear-gradient(0deg, #000 55%, #0000 0) bottom/100% 18.18%;
  background:
    linear-gradient(var(--loader-color, #f03355) 0 0) bottom/100% 0% no-repeat
    #ddd;
  animation: darma-loader-darma-custom-044-l8 2s infinite steps(7);
}
@keyframes darma-loader-darma-custom-044-l8 {
  100% { background-size: 100% 115%; }
}

